 {"id":"bd-13tp","title":"[TLS] Implement TlsConnector and TlsConnectorBuilder","description":"## Overview

Implement the `TlsConnector` and `TlsConnectorBuilder` for client-side TLS connections.

## Rationale

Client TLS is required for:
- HTTPS requests to external services
- gRPC clients connecting to servers
- Database connections (PostgreSQL, MySQL with TLS)
- Any secure outbound connection

## Implementation

### TlsConnector

```rust
// tls/src/connector.rs

use std::sync::Arc;
use std::io;
use rustls::{ClientConfig, ClientConnection, StreamOwned};
use rustls::pki_types::ServerName;

use crate::{Certificate, CertificateChain, PrivateKey, RootCertStore, TlsError, TlsStream};

/// Client-side TLS connector.
///
/// This is typically configured once and reused for many connections.
pub struct TlsConnector {
    config: Arc<ClientConfig>,
}

impl TlsConnector {
    /// Create from a raw rustls ClientConfig.
    pub fn new(config: ClientConfig) -> Self {
        TlsConnector {
            config: Arc::new(config),
        }
    }

    /// Create a builder for constructing a TlsConnector.
    pub fn builder() -> TlsConnectorBuilder {
        TlsConnectorBuilder::new()
    }

    /// Connect to a server, performing the TLS handshake.
    ///
    /// # Arguments
    /// * `domain` - The server name for SNI and certificate verification
    /// * `stream` - The underlying transport stream (TCP, etc.)
    ///
    /// # Cancel-Safety
    /// This method is NOT cancel-safe during handshake. If cancelled mid-handshake,
    /// the connection is in an undefined state and should be dropped.
    pub async fn connect<IO>(
        &self,
        domain: &str,
        stream: IO,
    ) -> Result<TlsStream<IO>, TlsError>
    where
        IO: AsyncRead + AsyncWrite + Unpin,
    {
        let server_name = ServerName::try_from(domain.to_string())
            .map_err(|_| TlsError::InvalidDnsName(domain.to_string()))?;

        tracing::debug!(domain = domain, "Starting TLS handshake");

        let conn = ClientConnection::new(self.config.clone(), server_name)
            .map_err(|e| TlsError::Handshake(e.to_string()))?;

        let mut tls_stream = TlsStream::new_client(stream, conn);

        // Perform the handshake
        tls_stream.handshake().await?;

        tracing::info!(
            domain = domain,
            protocol = ?tls_stream.protocol_version(),
            alpn = ?tls_stream.alpn_protocol(),
            "TLS handshake complete"
        );

        Ok(tls_stream)
    }

    /// Get the inner config (for advanced use).
    pub fn config(&self) -> &Arc<ClientConfig> {
        &self.config
    }
}

impl Clone for TlsConnector {
    fn clone(&self) -> Self {
        TlsConnector {
            config: self.config.clone(),
        }
    }
}
```

### TlsConnectorBuilder

```rust
// tls/src/connector.rs (continued)

/// Builder for `TlsConnector`.
pub struct TlsConnectorBuilder {
    root_certs: RootCertStore,
    client_identity: Option<(CertificateChain, PrivateKey)>,
    alpn_protocols: Vec<Vec<u8>>,
    enable_sni: bool,
    min_protocol: Option<rustls::ProtocolVersion>,
    max_protocol: Option<rustls::ProtocolVersion>,
}

impl TlsConnectorBuilder {
    /// Create a new builder with default settings.
    pub fn new() -> Self {
        TlsConnectorBuilder {
            root_certs: RootCertStore::empty(),
            client_identity: None,
            alpn_protocols: Vec::new(),
            enable_sni: true,
            min_protocol: None,
            max_protocol: None,
        }
    }

    /// Add platform/native root certificates.
    ///
    /// On Linux, this typically reads from /etc/ssl/certs.
    /// On macOS, this uses the system keychain.
    /// On Windows, this uses the Windows certificate store.
    pub fn with_native_roots(mut self) -> Result<Self, TlsError> {
        #[cfg(feature = "native-roots")]
        {
            for cert in rustls_native_certs::load_native_certs()
                .map_err(|e| TlsError::Certificate(e.to_string()))?
            {
                self.root_certs
                    .add(&Certificate::from_der(&cert.0))
                    .ok(); // Ignore individual cert errors
            }
            tracing::debug!(
                count = self.root_certs.len(),
                "Loaded native root certificates"
            );
        }

        #[cfg(not(feature = "native-roots"))]
        {
            return Err(TlsError::Configuration(
                "native-roots feature not enabled".into()
            ));
        }

        Ok(self)
    }

    /// Add the standard webpki root certificates.
    pub fn with_webpki_roots(mut self) -> Self {
        #[cfg(feature = "webpki-roots")]
        {
            self.root_certs.add_trust_anchors(
                webpki_roots::TLS_SERVER_ROOTS.iter().map(|ta| {
                    rustls::OwnedTrustAnchor::from_subject_spki_name_constraints(
                        ta.subject.to_vec(),
                        ta.subject_public_key_info.to_vec(),
                        ta.name_constraints.map(|nc| nc.to_vec()),
                    )
                })
            );
            tracing::debug!("Added webpki root certificates");
        }
        self
    }

    /// Add a single root certificate.
    pub fn add_root_certificate(mut self, cert: Certificate) -> Self {
        if let Err(e) = self.root_certs.add(&cert) {
            tracing::warn!(error = %e, "Failed to add root certificate");
        }
        self
    }

    /// Add multiple root certificates.
    pub fn add_root_certificates(mut self, certs: impl IntoIterator<Item = Certificate>) -> Self {
        for cert in certs {
            if let Err(e) = self.root_certs.add(&cert) {
                tracing::warn!(error = %e, "Failed to add root certificate");
            }
        }
        self
    }

    /// Set client certificate for mutual TLS.
    pub fn identity(mut self, chain: CertificateChain, key: PrivateKey) -> Self {
        self.client_identity = Some((chain, key));
        self
    }

    /// Set ALPN protocols (e.g., ["h2", "http/1.1"]).
    pub fn alpn_protocols(mut self, protocols: Vec<Vec<u8>>) -> Self {
        self.alpn_protocols = protocols;
        self
    }

    /// Convenience method for HTTP/2 ALPN.
    pub fn alpn_h2(self) -> Self {
        self.alpn_protocols(vec![b"h2".to_vec()])
    }

    /// Convenience method for HTTP/1.1 and HTTP/2 ALPN.
    pub fn alpn_http(self) -> Self {
        self.alpn_protocols(vec![b"h2".to_vec(), b"http/1.1".to_vec()])
    }

    /// Disable Server Name Indication (SNI).
    pub fn disable_sni(mut self) -> Self {
        self.enable_sni = false;
        self
    }

    /// Set minimum TLS protocol version.
    pub fn min_protocol_version(mut self, version: rustls::ProtocolVersion) -> Self {
        self.min_protocol = Some(version);
        self
    }

    /// Set maximum TLS protocol version.
    pub fn max_protocol_version(mut self, version: rustls::ProtocolVersion) -> Self {
        self.max_protocol = Some(version);
        self
    }

    /// Build the TlsConnector.
    pub fn build(self) -> Result<TlsConnector, TlsError> {
        if self.root_certs.is_empty() {
            tracing::warn!("Building TlsConnector with no root certificates");
        }

        let mut config = ClientConfig::builder()
            .with_safe_defaults()
            .with_root_certificates(self.root_certs.into());

        // Set client identity if provided
        let config = if let Some((chain, key)) = self.client_identity {
            config.with_client_auth_cert(chain.into(), key.into())
                .map_err(|e| TlsError::Configuration(e.to_string()))?
        } else {
            config.with_no_client_auth()
        };

        let mut config = config;

        // Set ALPN if specified
        if !self.alpn_protocols.is_empty() {
            config.alpn_protocols = self.alpn_protocols;
        }

        // SNI is enabled by default in rustls
        config.enable_sni = self.enable_sni;

        tracing::debug!(
            alpn = ?config.alpn_protocols,
            sni = config.enable_sni,
            "TlsConnector built"
        );

        Ok(TlsConnector::new(config))
    }
}

impl Default for TlsConnectorBuilder {
    fn default() -> Self {
        Self::new()
    }
}
```

