            .unwrap();

        let tls_stream = connector.connect("example.com", stream)
            .await
            .unwrap();

        debug!(
            version = ?tls_stream.protocol_version(),
            alpn = ?tls_stream.alpn_protocol(),
            "Connected to example.com"
        );

        assert!(tls_stream.protocol_version().is_some());
    }
