 {"id":"bd-kal4","title":"[Process] Implement Async Process Spawning with Cancel-Safety","description":"## Overview

Implement async process spawning with proper child I/O handling and cancel-safety.

## Rationale

Process spawning is needed for:
- Build systems and task runners
- CLI tools that call external commands
- Service orchestration
- Testing (spawning test servers)

## Implementation

### Command Builder

```rust
// process/src/command.rs

use std::ffi::{OsStr, OsString};
use std::path::{Path, PathBuf};
use std::collections::HashMap;
use std::process::Stdio;

use crate::{Child, ProcessError};

/// Builder for spawning a child process.
pub struct Command {
    program: OsString,
    args: Vec<OsString>,
    env: HashMap<OsString, OsString>,
    env_clear: bool,
    current_dir: Option<PathBuf>,
    stdin: Option<Stdio>,
    stdout: Option<Stdio>,
    stderr: Option<Stdio>,
    kill_on_drop: bool,
}

impl Command {
    /// Create a new command for the given program.
    pub fn new(program: impl AsRef<OsStr>) -> Self {
        Command {
            program: program.as_ref().to_owned(),
            args: Vec::new(),
            env: HashMap::new(),
            env_clear: false,
            current_dir: None,
            stdin: None,
            stdout: None,
            stderr: None,
            kill_on_drop: false,
        }
    }

    /// Add an argument.
    pub fn arg(mut self, arg: impl AsRef<OsStr>) -> Self {
        self.args.push(arg.as_ref().to_owned());
        self
    }

    /// Add multiple arguments.
    pub fn args(mut self, args: impl IntoIterator<Item = impl AsRef<OsStr>>) -> Self {
        self.args.extend(args.into_iter().map(|a| a.as_ref().to_owned()));
        self
    }

    /// Set an environment variable.
    pub fn env(mut self, key: impl AsRef<OsStr>, val: impl AsRef<OsStr>) -> Self {
        self.env.insert(key.as_ref().to_owned(), val.as_ref().to_owned());
        self
    }

    /// Set multiple environment variables.
    pub fn envs(mut self, vars: impl IntoIterator<Item = (impl AsRef<OsStr>, impl AsRef<OsStr>)>) -> Self {
        for (k, v) in vars {
            self.env.insert(k.as_ref().to_owned(), v.as_ref().to_owned());
        }
        self
    }

    /// Clear all environment variables before setting new ones.
    pub fn env_clear(mut self) -> Self {
        self.env_clear = true;
        self
    }

    /// Set the working directory.
    pub fn current_dir(mut self, dir: impl AsRef<Path>) -> Self {
        self.current_dir = Some(dir.as_ref().to_owned());
        self
    }

    /// Configure stdin.
    pub fn stdin(mut self, cfg: Stdio) -> Self {
        self.stdin = Some(cfg);
        self
    }

    /// Configure stdout.
    pub fn stdout(mut self, cfg: Stdio) -> Self {
        self.stdout = Some(cfg);
        self
    }

    /// Configure stderr.
    pub fn stderr(mut self, cfg: Stdio) -> Self {
        self.stderr = Some(cfg);
        self
    }

    /// Kill the process when the Child handle is dropped.
    ///
    /// This is crucial for cancel-safety: if the task spawning this process
    /// is cancelled, we want to clean up the child process.
    pub fn kill_on_drop(mut self, kill: bool) -> Self {
        self.kill_on_drop = kill;
        self
    }

    /// Spawn the process.
    pub fn spawn(self) -> Result<Child, ProcessError> {
        tracing::debug!(
            program = ?self.program,
            args = ?self.args,
            kill_on_drop = self.kill_on_drop,
            "Spawning process"
        );

        let mut cmd = std::process::Command::new(&self.program);
        cmd.args(&self.args);

        if self.env_clear {
            cmd.env_clear();
        }

        for (k, v) in &self.env {
            cmd.env(k, v);
        }

        if let Some(dir) = &self.current_dir {
            cmd.current_dir(dir);
        }

        cmd.stdin(self.stdin.unwrap_or(Stdio::null()));
        cmd.stdout(self.stdout.unwrap_or(Stdio::inherit()));
        cmd.stderr(self.stderr.unwrap_or(Stdio::inherit()));

        let child = cmd.spawn()
            .map_err(|e| ProcessError::Spawn(e.to_string()))?;

        let pid = child.id();
        tracing::info!(pid = pid, program = ?self.program, "Process spawned");

        Ok(Child::new(child, self.kill_on_drop))
    }

    /// Spawn and wait for completion, returning output.
    pub async fn output(self) -> Result<Output, ProcessError> {
        let mut child = self
            .stdin(Stdio::null())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()?;

        let stdout = child.stdout.take();
        let stderr = child.stderr.take();

        let (stdout_data, stderr_data) = tokio::join!(
            read_to_end(stdout),
            read_to_end(stderr)
        );

        let status = child.wait().await?;

        Ok(Output {
            status,
            stdout: stdout_data?,
            stderr: stderr_data?,
        })
    }

    /// Spawn and wait for completion, checking exit status.
    pub async fn status(self) -> Result<ExitStatus, ProcessError> {
        let mut child = self.spawn()?;
        child.wait().await
    }
}

async fn read_to_end(reader: Option<ChildStdout>) -> Result<Vec<u8>, ProcessError> {
    use tokio::io::AsyncReadExt;

    match reader {
        Some(mut r) => {
            let mut buf = Vec::new();
            r.read_to_end(&mut buf).await
                .map_err(|e| ProcessError::Io(e.to_string()))?;
            Ok(buf)
        }
        None => Ok(Vec::new()),
    }
}

/// Output of a finished process.
#[derive(Debug)]
pub struct Output {
    pub status: ExitStatus,
    pub stdout: Vec<u8>,
    pub stderr: Vec<u8>,
}

impl Output {
    /// Get stdout as a string (lossy).
    pub fn stdout_string(&self) -> String {
        String::from_utf8_lossy(&self.stdout).into_owned()
    }

    /// Get stderr as a string (lossy).
    pub fn stderr_string(&self) -> String {
        String::from_utf8_lossy(&self.stderr).into_owned()
    }
}
```

### Child Process

```rust
// process/src/child.rs

use std::process::{Child as StdChild, ExitStatus as StdExitStatus};
use tokio::io::{AsyncRead, AsyncWrite, ReadBuf};
use std::pin::Pin;
use std::task::{Context, Poll};

use crate::ProcessError;

/// Handle to a running child process.
pub struct Child {
    inner: Option<StdChild>,
    kill_on_drop: bool,
    pub stdin: Option<ChildStdin>,
    pub stdout: Option<ChildStdout>,
    pub stderr: Option<ChildStderr>,
}

impl Child {
    pub(crate) fn new(mut child: StdChild, kill_on_drop: bool) -> Self {
        let stdin = child.stdin.take().map(ChildStdin::new);
        let stdout = child.stdout.take().map(ChildStdout::new);
        let stderr = child.stderr.take().map(ChildStderr::new);

        Child {
            inner: Some(child),
            kill_on_drop,
            stdin,
            stdout,
            stderr,
        }
    }

    /// Get the process ID.
    pub fn id(&self) -> Option<u32> {
        self.inner.as_ref().map(|c| c.id())
    }

    /// Wait for the process to exit.
    pub async fn wait(&mut self) -> Result<ExitStatus, ProcessError> {
        use tokio::task;

        let mut child = self.inner.take()
            .ok_or(ProcessError::AlreadyWaited)?;

        let pid = child.id();
        tracing::debug!(pid = pid, "Waiting for process");

        // Use blocking task for waiting
        let status = task::spawn_blocking(move || child.wait())
            .await
            .map_err(|e| ProcessError::Internal(e.to_string()))?
            .map_err(|e| ProcessError::Wait(e.to_string()))?;

        let exit_status = ExitStatus::from(status);
        tracing::info!(pid = pid, status = ?exit_status, "Process exited");

        Ok(exit_status)
    }

    /// Kill the process.
    pub fn kill(&mut self) -> Result<(), ProcessError> {
        if let Some(ref mut child) = self.inner {
            let pid = child.id();
            tracing::warn!(pid = pid, "Killing process");
            child.kill().map_err(|e| ProcessError::Kill(e.to_string()))?;
        }
        Ok(())
    }

    /// Send a signal to the process (Unix only).
    #[cfg(unix)]
    pub fn signal(&self, signal: i32) -> Result<(), ProcessError> {
        use nix::sys::signal::{self, Signal};
        use nix::unistd::Pid;

        if let Some(ref child) = self.inner {
            let pid = Pid::from_raw(child.id() as i32);
            let sig = Signal::try_from(signal)
                .map_err(|_| ProcessError::Signal(format!("invalid signal: {}", signal)))?;

            tracing::debug!(pid = ?pid, signal = signal, "Sending signal");
            signal::kill(pid, sig)
                .map_err(|e| ProcessError::Signal(e.to_string()))?;
        }
        Ok(())
    }

    /// Try to get the exit status without blocking.
    pub fn try_wait(&mut self) -> Result<Option<ExitStatus>, ProcessError> {
        if let Some(ref mut child) = self.inner {
            match child.try_wait() {
                Ok(Some(status)) => {
                    self.inner = None;
                    Ok(Some(ExitStatus::from(status)))
                }
                Ok(None) => Ok(None),
                Err(e) => Err(ProcessError::Wait(e.to_string())),
            }
        } else {
            Err(ProcessError::AlreadyWaited)
        }
    }

    /// Take stdin handle.
    pub fn take_stdin(&mut self) -> Option<ChildStdin> {
        self.stdin.take()
    }

    /// Take stdout handle.
    pub fn take_stdout(&mut self) -> Option<ChildStdout> {
        self.stdout.take()
    }

    /// Take stderr handle.
    pub fn take_stderr(&mut self) -> Option<ChildStderr> {
        self.stderr.take()
    }
}

impl Drop for Child {
    fn drop(&mut self) {
        if self.kill_on_drop {
            if let Some(ref mut child) = self.inner {
                let pid = child.id();
                tracing::debug!(pid = pid, "Killing process on drop (kill_on_drop=true)");
                let _ = child.kill();
            }
        }
    }
}

/// Exit status of a process.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ExitStatus {
    code: Option<i32>,
    #[cfg(unix)]
    signal: Option<i32>,
}

impl ExitStatus {
    /// Returns true if the process exited successfully (code 0).
    pub fn success(&self) -> bool {
        self.code == Some(0)
    }

    /// Get the exit code (if exited normally).
    pub fn code(&self) -> Option<i32> {
        self.code
    }

    /// Get the signal that terminated the process (Unix only).
    #[cfg(unix)]
    pub fn signal(&self) -> Option<i32> {
        self.signal
    }
}

impl From<StdExitStatus> for ExitStatus {
    fn from(status: StdExitStatus) -> Self {
        ExitStatus {
            code: status.code(),
            #[cfg(unix)]
            signal: {
                use std::os::unix::process::ExitStatusExt;
                status.signal()
            },
        }
    }
}

/// Child's stdin.
pub struct ChildStdin {
    inner: tokio::process::ChildStdin,
}

impl ChildStdin {
    fn new(stdin: std::process::ChildStdin) -> Self {
        ChildStdin {
            inner: tokio::process::ChildStdin::from_std(stdin).unwrap(),
        }
    }
}

impl AsyncWrite for ChildStdin {
    fn poll_write(
        mut self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &[u8],
    ) -> Poll<std::io::Result<usize>> {
        Pin::new(&mut self.inner).poll_write(cx, buf)
    }

    fn poll_flush(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<std::io::Result<()>> {
        Pin::new(&mut self.inner).poll_flush(cx)
    }

    fn poll_shutdown(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<std::io::Result<()>> {
        Pin::new(&mut self.inner).poll_shutdown(cx)
    }
}

/// Child's stdout.
pub struct ChildStdout {
    inner: tokio::process::ChildStdout,
}

impl ChildStdout {
    fn new(stdout: std::process::ChildStdout) -> Self {
        ChildStdout {
            inner: tokio::process::ChildStdout::from_std(stdout).unwrap(),
        }
    }
}

impl AsyncRead for ChildStdout {
    fn poll_read(
        mut self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &mut ReadBuf<'_>,
    ) -> Poll<std::io::Result<()>> {
        Pin::new(&mut self.inner).poll_read(cx, buf)
    }
}

/// Child's stderr.
pub struct ChildStderr {
    inner: tokio::process::ChildStderr,
}

impl ChildStderr {
    fn new(stderr: std::process::ChildStderr) -> Self {
        ChildStderr {
            inner: tokio::process::ChildStderr::from_std(stderr).unwrap(),
        }
    }
}

impl AsyncRead for ChildStderr {
    fn poll_read(
        mut self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &mut ReadBuf<'_>,
    ) -> Poll<std::io::Result<()>> {
        Pin::new(&mut self.inner).poll_read(cx, buf)
    }
}
