```rust
#[cfg(test)]
mod tests {
    use super::*;
    use tokio::io::{AsyncReadExt, AsyncWriteExt};
    use tracing::{info, debug};

    #[tokio::test]
    async fn test_command_output() {
        info!("Testing Command::output()");

        let output = Command::new("echo")
            .arg("hello")
            .output()
            .await
            .unwrap();

        assert!(output.status.success());
        assert_eq!(output.stdout_string().trim(), "hello");
        debug!(stdout = output.stdout_string().trim(), "Command output");
    }

    #[tokio::test]
    async fn test_command_status() {
        info!("Testing Command::status()");

        let status = Command::new("true")
            .status()
            .await
            .unwrap();

        assert!(status.success());
        assert_eq!(status.code(), Some(0));
    }

    #[tokio::test]
    async fn test_command_failure() {
        info!("Testing command failure");

        let status = Command::new("false")
            .status()
            .await
            .unwrap();

        assert!(!status.success());
        assert_eq!(status.code(), Some(1));
    }

    #[tokio::test]
    async fn test_command_stdin_stdout() {
        info!("Testing stdin/stdout piping");

        let mut child = Command::new("cat")
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .spawn()
            .unwrap();

        let mut stdin = child.take_stdin().unwrap();
        let mut stdout = child.take_stdout().unwrap();

        stdin.write_all(b"hello from stdin").await.unwrap();
        drop(stdin); // Close stdin

        let mut output = String::new();
        stdout.read_to_string(&mut output).await.unwrap();

        assert_eq!(output, "hello from stdin");

        let status = child.wait().await.unwrap();
        assert!(status.success());
    }

    #[tokio::test]
    async fn test_command_env() {
        info!("Testing environment variables");

        let output = Command::new("sh")
            .arg("-c")
            .arg("echo $MY_VAR")
            .env("MY_VAR", "hello_env")
            .output()
            .await
            .unwrap();

        assert_eq!(output.stdout_string().trim(), "hello_env");
    }

    #[tokio::test]
    async fn test_command_current_dir() {
        info!("Testing current directory");

        let output = Command::new("pwd")
            .current_dir("/tmp")
            .output()
            .await
            .unwrap();

        assert!(output.stdout_string().trim().starts_with("/tmp"));
    }

    #[tokio::test]
    async fn test_kill_on_drop() {
        info!("Testing kill_on_drop");

        let start = std::time::Instant::now();

        {
            let _child = Command::new("sleep")
                .arg("60")
                .kill_on_drop(true)
                .spawn()
                .unwrap();

            // Child dropped here - should be killed
        }

        let elapsed = start.elapsed();
        assert!(elapsed.as_secs() < 5, "Process should have been killed");
        debug!(elapsed_ms = elapsed.as_millis(), "kill_on_drop worked");
    }

    #[tokio::test]
    async fn test_try_wait() {
        info!("Testing try_wait");

        let mut child = Command::new("sleep")
            .arg("0.1")
            .spawn()
            .unwrap();

        // Should not be done yet
        assert!(child.try_wait().unwrap().is_none());

        // Wait for completion
        tokio::time::sleep(std::time::Duration::from_millis(200)).await;

        // Now should be done
        let status = child.try_wait().unwrap();
        assert!(status.is_some());
        assert!(status.unwrap().success());
    }

    #[tokio::test]
    #[cfg(unix)]
    async fn test_signal() {
        info!("Testing signal sending");

        let mut child = Command::new("sleep")
            .arg("60")
            .spawn()
            .unwrap();

        // Send SIGTERM
        child.signal(15).unwrap(); // SIGTERM = 15

        let status = child.wait().await.unwrap();
        assert!(!status.success());
        assert_eq!(status.signal(), Some(15));
    }
}
